// LAYER 1+2: Extract & Validate (§4.1 PRE-validate)
// Zero-throw: returns Standard Contract error, never throws

const raw = $input.first().json;
const input = (raw.body && typeof raw.body === 'object') ? raw.body : raw;

// ISO 8601 with timezone validation
function isIsoDate(str) {
  if (!str || !str.includes('T')) return false;
  const tzMatch = str.match(/(Z|[+-]\d{2}:\d{2})$/);
  if (!tzMatch) return false;
  const d = new Date(str);
  if (isNaN(d.getTime())) return false;
  const parts = str.match(/^(\d{4})-(\d{2})-(\d{2})T/);
  if (!parts) return false;
  const [_, year, month, day] = parts;
  if (parseInt(month) !== d.getUTCMonth() + 1) return false;
  if (parseInt(day) !== d.getUTCDate()) return false;
  return true;
}

function ve(code, msg) {
  return [{ json: {
    success: false, error_code: code, error_message: msg, data: null,
    _meta: { source: 'WF5_GCal_Collision_Check', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
    _exit_early: true
  }}];
}

// === START_TIME VALIDATION ===
const start_time = String(input.start_time || '').trim();
if (!start_time) return ve('MISSING_FIELD', 'start_time is required');
if (!isIsoDate(start_time)) return ve('INVALID_TYPE', 'start_time must be ISO 8601 with timezone (e.g. 2026-04-15T09:00:00-03:00)');

// === DURATION VALIDATION ===
let duration_minutes = 60; // default
if (input.duration_minutes !== undefined && input.duration_minutes !== null) {
  const durStr = String(input.duration_minutes).trim();
  const INT_RE = /^\d+$/;
  if (!INT_RE.test(durStr)) return ve('INVALID_TYPE', 'duration_minutes must be a positive integer');
  duration_minutes = parseInt(durStr);
  if (duration_minutes < 5 || duration_minutes > 1440) return ve('INVALID_RANGE', 'duration must be between 5 and 1440 minutes');
}

// === CALENDAR_ID (optional, default 'primary') ===
const calendar_id = String(input.calendar_id || 'primary').trim();

// === EXCLUDE_EVENT_ID (optional) ===
let exclude_event_id = null;
if (input.exclude_event_id !== undefined && input.exclude_event_id !== null) {
  exclude_event_id = String(input.exclude_event_id).trim();
}

// Calculate end_time
const startDate = new Date(start_time);
const endDate = new Date(startDate.getTime() + duration_minutes * 60000);

return [{ json: {
  success: true,
  calendar_id,
  start_time: startDate.toISOString(),
  end_time: endDate.toISOString(),
  duration_minutes,
  exclude_event_id,
  _validated: true
}}];

// Handle GCal API error
const e = $input.first().json;
const upstreamData = $('Validate Input').isExecuted ? $('Validate Input').first().json : {};
let error_code = 'GCAL_API_ERROR';
let error_message = e.message || e.error?.message || 'Google Calendar API error';

if (error_message.includes('invalid_grant') || error_message.includes('unauthorized')) {
  error_code = 'GCAL_AUTH_ERROR';
  error_message = 'Google Calendar authentication failed';
} else if (error_message.includes('quota') || error_message.includes('rate limit')) {
  error_code = 'GCAL_QUOTA_EXCEEDED';
  error_message = 'Google Calendar API quota exceeded';
}

return [{ json: {
  ...upstreamData,
  success: false, error_code, error_message, data: null,
  _meta: { source: 'WF5_GCal_Collision_Check', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];

// Analyze overlaps and detect collisions
const items = $input.all();
const upstreamData = $('Validate Input').isExecuted ? $('Validate Input').first().json : {};

const reqStart = new Date(upstreamData.start_time).getTime();
const reqEnd = new Date(upstreamData.end_time).getTime();
const excludeId = upstreamData.exclude_event_id;

const conflicts = items.filter(item => {
  const ev = item.json;
  if (!ev || !ev.id || ev.status === 'cancelled' || ev.id === excludeId) return false;
  const evStart = new Date(ev.start?.dateTime || ev.start?.date).getTime();
  const evEnd = new Date(ev.end?.dateTime || ev.end?.date).getTime();
  // Check overlap: reqStart < evEnd && reqEnd > evStart
  return reqStart < evEnd && reqEnd > evStart;
}).map(c => ({
  id: c.json.id,
  summary: c.json.summary || 'Untitled',
  start: c.json.start?.dateTime || c.json.start?.date
}));

return [{ json: {
  ...upstreamData,
  _success: true,
  has_collision: conflicts.length > 0,
  conflicts
}}];

// UNIFIED OUTPUT — Standard Contract (§3.2)
const input = $input.first().json;

// Process items that have data OR error_code set
if (input.data !== undefined || input.error_code !== undefined) {
  return [{ json: {
    success: input.success === true,
    error_code: input.error_code || null,
    error_message: input.error_message || null,
    data: input.data || null,
    _meta: input._meta || {
      source: 'WF5_GCal_Collision_Check',
      timestamp: new Date().toISOString(),
      workflow_id: $workflow.id
    }
  }}];
}

// Items with _success flag from Analyze Overlaps
if (input._success === true) {
  return [{ json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      slot_available: !input.has_collision,
      has_collision: input.has_collision,
      conflicts: input.conflicts || [],
      checked_at: new Date().toISOString()
    },
    _meta: {
      source: 'WF5_GCal_Collision_Check',
      timestamp: new Date().toISOString(),
      workflow_id: $workflow.id
    }
  }}];
}

// Otherwise, pass-through item — skip it
return [];
